#ifndef COMMAND_HPP
#define COMMAND_HPP
#include <string>
#include <vector>
#include <sstream>
#include <iomanip>
#include <set>
#include <iostream>
#include <cstdlib>
#include "account.hpp"
#include "book.hpp"
#include "log.hpp"
class CommandProcessor {
private:
    AccountSystem& accounts; BookSystem& books; LogSystem& logs; int selected_book_pos;
    std::vector<std::string> split(const std::string& str, char delim = ' ') { std::vector<std::string> tokens; std::string token; std::istringstream iss(str); while (std::getline(iss, token, delim)) if (!token.empty()) tokens.push_back(token); return tokens; }
    std::string strip(const std::string& str) { size_t start = str.find_first_not_of(" \t\n\r"); if (start == std::string::npos) return ""; size_t end = str.find_last_not_of(" \t\n\r"); return str.substr(start, end - start + 1); }
    bool isValidNumber(const std::string& s) { if (s.empty()) return false; for (char c : s) if (!std::isdigit(c)) return false; return true; }
    bool isValidPrice(const std::string& s) { if (s.empty()) return false; int d = 0; for (char c : s) { if (c == '.') d++; else if (!std::isdigit(c)) return false; } return d <= 1; }
    std::string formatPrice(double price) { std::ostringstream oss; oss << std::fixed << std::setprecision(2) << price; return oss.str(); }
    void printBooks(const std::vector<BookData>& bl) { if (bl.empty()) { std::cout << "\n"; return; } for (const auto& b : bl) std::cout << b.isbn << "\t" << b.name << "\t" << b.author << "\t" << b.keywords << "\t" << formatPrice(b.price) << "\t" << b.stock << "\n"; }
public:
    CommandProcessor(AccountSystem& acc, BookSystem& bk, LogSystem& lg) : accounts(acc), books(bk), logs(lg), selected_book_pos(-1) {}
    void processCommand(const std::string& line) {
        std::string cmd = strip(line); if (cmd.empty()) return; std::vector<std::string> tok = split(cmd); if (tok.empty()) return; const std::string& op = tok[0];
        if (op == "quit" || op == "exit") std::exit(0);
        else if (op == "su") handleSu(tok); else if (op == "logout") handleLogout(); else if (op == "register") handleRegister(tok); else if (op == "passwd") handlePasswd(tok);
        else if (op == "useradd") handleUseradd(tok); else if (op == "delete") handleDelete(tok); else if (op == "show") handleShow(tok); else if (op == "buy") handleBuy(tok);
        else if (op == "select") handleSelect(tok); else if (op == "modify") handleModify(tok); else if (op == "import") handleImport(tok); else if (op == "log") handleLog();
        else std::cout << "Invalid\n";
    }
private:
    void handleSu(const std::vector<std::string>& tok) { if (tok.size() < 2 || tok.size() > 3) { std::cout << "Invalid\n"; return; } std::string uid = tok[1], pwd = (tok.size() > 2) ? tok[2] : ""; if (!accounts.su(uid, pwd)) { std::cout << "Invalid\n"; return; } selected_book_pos = -1; std::string sel = accounts.getSelectedBook(); if (!sel.empty()) books.select(sel, selected_book_pos); }
    void handleLogout() { if (accounts.getCurrentPrivilege() < 1 || !accounts.logout()) { std::cout << "Invalid\n"; return; } selected_book_pos = -1; if (accounts.isLoggedIn()) { std::string sel = accounts.getSelectedBook(); if (!sel.empty()) books.select(sel, selected_book_pos); } }
    void handleRegister(const std::vector<std::string>& tok) { if (tok.size() != 4 || !accounts.registerUser(tok[1], tok[2], tok[3])) std::cout << "Invalid\n"; }
    void handlePasswd(const std::vector<std::string>& tok) { if (tok.size() < 3 || tok.size() > 4 || accounts.getCurrentPrivilege() < 1) { std::cout << "Invalid\n"; return; } std::string uid = tok[1], npw, opw; if (tok.size() == 3) { if (accounts.getCurrentPrivilege() != 7) { std::cout << "Invalid\n"; return; } npw = tok[2]; } else { opw = tok[2]; npw = tok[3]; } if (!accounts.passwd(uid, npw, opw)) std::cout << "Invalid\n"; }
    void handleUseradd(const std::vector<std::string>& tok) { if (tok.size() != 5 || accounts.getCurrentPrivilege() < 3) { std::cout << "Invalid\n"; return; } int priv; try { priv = std::stoi(tok[3]); } catch (...) { std::cout << "Invalid\n"; return; } if (!accounts.useradd(tok[1], tok[2], priv, tok[4])) std::cout << "Invalid\n"; }
    void handleDelete(const std::vector<std::string>& tok) { if (tok.size() != 2 || accounts.getCurrentPrivilege() < 7 || !accounts.deleteUser(tok[1])) std::cout << "Invalid\n"; }
    void handleShow(const std::vector<std::string>& tok) { if (accounts.getCurrentPrivilege() < 1) { std::cout << "Invalid\n"; return; } if (tok.size() == 1) { printBooks(books.showAll()); return; } if (tok[1] == "finance") { handleShowFinance(tok); return; } if (tok.size() != 2) { std::cout << "Invalid\n"; return; } const std::string& p = tok[1]; if (p.substr(0, 5) == "-ISBN") printBooks(books.showByISBN(p.substr(6))); else if (p.substr(0, 5) == "-name") { size_t s = p.find('"'), e = p.rfind('"'); if (s == std::string::npos || e == std::string::npos || s == e) { std::cout << "Invalid\n"; return; } printBooks(books.showByName(p.substr(s + 1, e - s - 1))); } else if (p.substr(0, 7) == "-author") { size_t s = p.find('"'), e = p.rfind('"'); if (s == std::string::npos || e == std::string::npos || s == e) { std::cout << "Invalid\n"; return; } printBooks(books.showByAuthor(p.substr(s + 1, e - s - 1))); } else if (p.substr(0, 8) == "-keyword") { size_t s = p.find('"'), e = p.rfind('"'); if (s == std::string::npos || e == std::string::npos || s == e) { std::cout << "Invalid\n"; return; } std::string kw = p.substr(s + 1, e - s - 1); if (kw.empty()) { std::cout << "Invalid\n"; return; } printBooks(books.showByKeyword(kw)); } else std::cout << "Invalid\n"; }
    void handleShowFinance(const std::vector<std::string>& tok) { if (accounts.getCurrentPrivilege() < 7) { std::cout << "Invalid\n"; return; } if (tok.size() == 2) { auto r = logs.showAllFinance(); std::cout << "+ " << formatPrice(r.first) << " - " << formatPrice(r.second) << "\n"; } else if (tok.size() == 3) { int c; try { c = std::stoi(tok[2]); } catch (...) { std::cout << "Invalid\n"; return; } if (c == 0) { std::cout << "\n"; return; } auto r = logs.showFinance(c); if (r.first < 0) { std::cout << "Invalid\n"; return; } std::cout << "+ " << formatPrice(r.first) << " - " << formatPrice(r.second) << "\n"; } else std::cout << "Invalid\n"; }
    void handleBuy(const std::vector<std::string>& tok) { if (accounts.getCurrentPrivilege() < 1 || tok.size() != 3 || !isValidNumber(tok[2])) { std::cout << "Invalid\n"; return; } int qty; try { qty = std::stoi(tok[2]); } catch (...) { std::cout << "Invalid\n"; return; } double tp; int pos; if (!books.buy(tok[1], qty, tp, pos)) { std::cout << "Invalid\n"; return; } std::cout << formatPrice(tp) << "\n"; logs.addFinance(tp, 0, accounts.getCurrentUserId(), tok[1], qty, "buy"); }
    void handleSelect(const std::vector<std::string>& tok) { if (accounts.getCurrentPrivilege() < 3 || tok.size() != 2) { std::cout << "Invalid\n"; return; } if (!books.select(tok[1], selected_book_pos)) { std::cout << "Invalid\n"; return; } accounts.selectBook(tok[1]); }
    void handleModify(const std::vector<std::string>& tok) { if (accounts.getCurrentPrivilege() < 3 || selected_book_pos < 0 || tok.size() < 2) { std::cout << "Invalid\n"; return; } std::string nis, nn, na, nk; double np = 0; bool his = false, hn = false, ha = false, hk = false, hp = false; std::set<std::string> seen; for (size_t i = 1; i < tok.size(); i++) { const std::string& p = tok[i]; if (p.substr(0, 5) == "-ISBN") { if (seen.count("-ISBN")) { std::cout << "Invalid\n"; return; } seen.insert("-ISBN"); nis = p.substr(6); his = true; } else if (p.substr(0, 5) == "-name") { if (seen.count("-name")) { std::cout << "Invalid\n"; return; } seen.insert("-name"); size_t s = p.find('"'), e = p.rfind('"'); if (s == std::string::npos || e == std::string::npos || s == e) { std::cout << "Invalid\n"; return; } nn = p.substr(s + 1, e - s - 1); if (nn.empty()) { std::cout << "Invalid\n"; return; } hn = true; } else if (p.substr(0, 7) == "-author") { if (seen.count("-author")) { std::cout << "Invalid\n"; return; } seen.insert("-author"); size_t s = p.find('"'), e = p.rfind('"'); if (s == std::string::npos || e == std::string::npos || s == e) { std::cout << "Invalid\n"; return; } na = p.substr(s + 1, e - s - 1); if (na.empty()) { std::cout << "Invalid\n"; return; } ha = true; } else if (p.substr(0, 8) == "-keyword") { if (seen.count("-keyword")) { std::cout << "Invalid\n"; return; } seen.insert("-keyword"); size_t s = p.find('"'), e = p.rfind('"'); if (s == std::string::npos || e == std::string::npos || s == e) { std::cout << "Invalid\n"; return; } nk = p.substr(s + 1, e - s - 1); if (nk.empty()) { std::cout << "Invalid\n"; return; } hk = true; } else if (p.substr(0, 6) == "-price") { if (seen.count("-price")) { std::cout << "Invalid\n"; return; } seen.insert("-price"); std::string ps = p.substr(7); if (!isValidPrice(ps)) { std::cout << "Invalid\n"; return; } try { np = std::stod(ps); } catch (...) { std::cout << "Invalid\n"; return; } hp = true; } else { std::cout << "Invalid\n"; return; } } if (!books.modify(selected_book_pos, nis, nn, na, nk, np, his, hn, ha, hk, hp)) { std::cout << "Invalid\n"; return; } if (his) accounts.selectBook(nis); }
    void handleImport(const std::vector<std::string>& tok) { if (accounts.getCurrentPrivilege() < 3 || selected_book_pos < 0 || tok.size() != 3) { std::cout << "Invalid\n"; return; } if (!isValidNumber(tok[1]) || !isValidPrice(tok[2])) { std::cout << "Invalid\n"; return; } int qty; double tc; try { qty = std::stoi(tok[1]); tc = std::stod(tok[2]); } catch (...) { std::cout << "Invalid\n"; return; } if (!books.import(selected_book_pos, qty, tc)) { std::cout << "Invalid\n"; return; } logs.addFinance(0, tc, accounts.getCurrentUserId(), books.getISBN(selected_book_pos), qty, "import"); }
    void handleLog() { if (accounts.getCurrentPrivilege() < 7) { std::cout << "Invalid\n"; return; } std::cout << logs.getLog(); }
};
#endif
